import React, { useState, useEffect } from 'react';
import axios from 'axios';

/**
 * Tasks page component with CRUD functionality
 */
const Tasks = () => {
  const [tasks, setTasks] = useState([]);
  const [newTask, setNewTask] = useState({ title: '', description: '', status: 'pending', assignedTo: '', priority: 'medium' });
  const [loading, setLoading] = useState(true);

  // Fetch tasks on component mount
  useEffect(() => {
    fetchTasks();
  }, []);

  /**
   * Fetch all tasks from backend
   */
  const fetchTasks = async () => {
    try {
      const response = await axios.get('http://localhost:5000/api/tasks');
      setTasks(response.data);
    } catch (error) {
      console.error('Error fetching tasks:', error);
    } finally {
      setLoading(false);
    }
  };

  /**
   * Handle adding a new task
   */
  const handleAddTask = async (e) => {
    e.preventDefault();
    try {
      const response = await axios.post('http://localhost:5000/api/tasks', newTask);
      setTasks([...tasks, response.data]);
      setNewTask({ title: '', description: '', status: 'pending', assignedTo: '', priority: 'medium' });
    } catch (error) {
      console.error('Error adding task:', error);
    }
  };

  /**
   * Handle deleting a task
   */
  const handleDeleteTask = async (id) => {
    try {
      await axios.delete(`http://localhost:5000/api/tasks/${id}`);
      setTasks(tasks.filter(task => task._id !== id));
    } catch (error) {
      console.error('Error deleting task:', error);
    }
  };

  if (loading) {
    return <div className="p-6">Loading tasks...</div>;
  }

  return (
    <div className="p-6">
      <h2 className="text-2xl font-bold mb-4">Tasks</h2>

      {/* Add Task Form */}
      <form onSubmit={handleAddTask} className="mb-6 bg-gray-800 p-4 rounded">
        <h3 className="text-lg font-semibold mb-2">Add New Task</h3>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <input
            type="text"
            placeholder="Task Title"
            value={newTask.title}
            onChange={(e) => setNewTask({ ...newTask, title: e.target.value })}
            className="p-2 bg-gray-700 text-white rounded"
            required
          />
          <input
            type="text"
            placeholder="Assigned To"
            value={newTask.assignedTo}
            onChange={(e) => setNewTask({ ...newTask, assignedTo: e.target.value })}
            className="p-2 bg-gray-700 text-white rounded"
          />
          <select
            value={newTask.status}
            onChange={(e) => setNewTask({ ...newTask, status: e.target.value })}
            className="p-2 bg-gray-700 text-white rounded"
          >
            <option value="pending">Pending</option>
            <option value="in-progress">In Progress</option>
            <option value="completed">Completed</option>
          </select>
          <select
            value={newTask.priority}
            onChange={(e) => setNewTask({ ...newTask, priority: e.target.value })}
            className="p-2 bg-gray-700 text-white rounded"
          >
            <option value="low">Low</option>
            <option value="medium">Medium</option>
            <option value="high">High</option>
          </select>
        </div>
        <textarea
          placeholder="Description"
          value={newTask.description}
          onChange={(e) => setNewTask({ ...newTask, description: e.target.value })}
          className="w-full p-2 bg-gray-700 text-white rounded mt-2"
          rows="3"
        />
        <button type="submit" className="mt-2 bg-blue-600 px-4 py-2 rounded hover:bg-blue-700">
          Add Task
        </button>
      </form>

      {/* Tasks Table */}
      <div className="bg-gray-800 rounded overflow-hidden">
        <table className="w-full">
          <thead className="bg-gray-700">
            <tr>
              <th className="p-3 text-left">Title</th>
              <th className="p-3 text-left">Status</th>
              <th className="p-3 text-left">Priority</th>
              <th className="p-3 text-left">Assigned To</th>
              <th className="p-3 text-left">Actions</th>
            </tr>
          </thead>
          <tbody>
            {tasks.map(task => (
              <tr key={task._id} className="border-t border-gray-600">
                <td className="p-3">{task.title}</td>
                <td className="p-3">
                  <span className={`px-2 py-1 rounded text-xs ${
                    task.status === 'completed' ? 'bg-green-600' :
                    task.status === 'in-progress' ? 'bg-yellow-600' : 'bg-gray-600'
                  }`}>
                    {task.status}
                  </span>
                </td>
                <td className="p-3">
                  <span className={`px-2 py-1 rounded text-xs ${
                    task.priority === 'high' ? 'bg-red-600' :
                    task.priority === 'medium' ? 'bg-yellow-600' : 'bg-green-600'
                  }`}>
                    {task.priority}
                  </span>
                </td>
                <td className="p-3">{task.assignedTo}</td>
                <td className="p-3">
                  <button
                    onClick={() => handleDeleteTask(task._id)}
                    className="bg-red-600 px-3 py-1 rounded hover:bg-red-700 text-sm"
                  >
                    Delete
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
        {tasks.length === 0 && (
          <div className="p-6 text-center text-gray-400">No tasks found. Add your first task above.</div>
        )}
      </div>
    </div>
  );
};

export default Tasks;
